from ariadne import QueryType, make_executable_schema, gql, graphql_sync
from ariadne.asgi import GraphQL
from starlette.middleware.authentication import AuthenticationMiddleware
from starlette.applications import Starlette
from starlette.responses import JSONResponse
from starlette.routing import Route
from starlette.authentication import AuthenticationBackend, AuthCredentials, SimpleUser
from starlette.requests import Request

# Sample data
users = {
    1: {"username": "john_doe", "bio": "Developer", "email": "john@example.com", "phone": "123-456-7890", "address": "123 Main St"},
    2: {"username": "jane_doe", "bio": "Designer", "email": "jane@example.com", "phone": "987-654-3210", "address": "456 Elm St"},
}

# GraphQL schema
type_defs = gql("""
    type User {
        username: String!
        bio: String!
        email: String
        phone: String
        address: String
    }

    type Query {
        userProfile: User
    }
""")

query = QueryType()

@query.field("userProfile")
def resolve_user_profile(_, info):
    current_user = info.context["current_user"]
    user = users.get(current_user.id)
    if user:
        return {
            "username": user["username"],
            "bio": user["bio"],
            "email": user["email"],
            "phone": user["phone"],
            "address": user["address"],
        }
    return None

schema = make_executable_schema(type_defs, query)

class SimpleAuthBackend(AuthenticationBackend):
    async def authenticate(self, request):
        # Simulate authentication
        user_id = request.headers.get("X-User-ID")
        if user_id and user_id in users:
            return AuthCredentials(["authenticated"]), SimpleUser(user_id)
        return None

app = Starlette(debug=True)
app.add_middleware(AuthenticationMiddleware, backend=SimpleAuthBackend())

@app.route("/graphql", methods=["POST"])
async def graphql_server(request: Request):
    data = await request.json()
    success, result = graphql_sync(schema, data, context_value={"current_user": request.user})
    status = 200 if success else 400
    return JSONResponse(result, status_code=status)

app.mount("/graphql", GraphQL(schema, debug=True))